function fmtMiB(value) {
  const api = displayFormattersApi();
  if (api && typeof api.fmtMiB === "function") return api.fmtMiB(value);
  const n = Number(value || 0);
  if (n >= 1024) return `${(n / 1024).toFixed(1)} GiB`;
  return `${n} MiB`;
}

function formatBytes(value) {
  const api = displayFormattersApi();
  if (api && typeof api.formatBytes === "function") return api.formatBytes(value);
  let n = Number(value || 0);
  if (!Number.isFinite(n) || n <= 0) return "0 B";
  const units = ["B", "KiB", "MiB", "GiB", "TiB", "PiB"];
  let index = 0;
  while (n >= 1024 && index < units.length - 1) {
    n /= 1024;
    index += 1;
  }
  if (index === 0) return `${Math.round(n)} ${units[index]}`;
  return `${n.toFixed(n >= 10 ? 1 : 2)} ${units[index]}`;
}

function formatPercent(value) {
  const api = displayFormattersApi();
  if (api && typeof api.formatPercent === "function") return api.formatPercent(value);
  const n = Number(value);
  if (!Number.isFinite(n)) return "--";
  return `${Math.max(0, Math.min(100, n)).toFixed(n % 1 === 0 ? 0 : 1)}%`;
}

function inputParsersApi() {
  return window.InputParsers && typeof window.InputParsers === "object" ? window.InputParsers : null;
}

function positiveNumberOrBlank(value) {
  const api = inputParsersApi();
  if (api && typeof api.positiveNumberOrBlank === "function") return api.positiveNumberOrBlank(value);
  const n = Number(value);
  return Number.isFinite(n) && n > 0 ? n : "";
}

function escapeHtml(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

function stripAnsi(value) {
  return String(value || "")
    .replace(/\uFFFD\[[0-?]*[ -/]*[@-~]/g, "")
    .replace(/\x1b\[[0-?]*[ -/]*[@-~]/g, "")
    .replace(/\x1b\][^\x07]*(?:\x07|\x1b\\)/g, "")
    .replace(/\x1b[()#%*+\-.\/][0-9A-Za-z]/g, "")
    .replace(/[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]/g, "");
}

function fmtDate(value) {
  if (!value) return "";
  return String(value).replace("T", " ").slice(0, 16);
}

function deepClone(value, fallback) {
  try {
    return JSON.parse(JSON.stringify(value));
  } catch {
    return fallback;
  }
}

function makeClientId(prefix = "node") {
  if (globalThis.crypto?.randomUUID) return `${prefix}-${globalThis.crypto.randomUUID()}`;
  return `${prefix}-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
}

// Editor inputs trigger a state update that re-renders the panel via innerHTML,
// which rebuilds the focused input and drops focus/caret mid-keystroke. Wrap any
// input-driven render with this so the active field is refocused afterwards.
function _inputSignature(el) {
  const data = el.dataset
    ? Object.keys(el.dataset).sort().map((k) => `${k}=${el.dataset[k]}`).join("|")
    : "";
  return `${el.tagName}|${el.type || ""}|${el.name || ""}|${data}`;
}

function _findInputBySignature(sig) {
  let match = null;
  for (const el of document.querySelectorAll("input, textarea, select")) {
    if (_inputSignature(el) === sig) {
      if (match) return null; // ambiguous — refuse to guess
      match = el;
    }
  }
  return match;
}

function captureActiveInput() {
  const active = document.activeElement;
  if (!active || !/^(INPUT|TEXTAREA|SELECT)$/.test(active.tagName)) return null;
  let start = null;
  let end = null;
  try {
    start = active.selectionStart;
    end = active.selectionEnd;
  } catch (_) {
    start = end = null;
  }
  return { sig: _inputSignature(active), start, end };
}

function restoreActiveInput(captured) {
  if (!captured) return;
  const match = _findInputBySignature(captured.sig);
  if (!match) return;
  match.focus();
  if (captured.start !== null) {
    try {
      match.setSelectionRange(captured.start, captured.end);
    } catch (_) {
      /* not all elements support selection */
    }
  }
}

function preserveActiveInput(renderFn) {
  const captured = captureActiveInput();
  renderFn();
  restoreActiveInput(captured);
}


function parseLineList(value) {
  const api = inputParsersApi();
  if (api && typeof api.parseLineList === "function") return api.parseLineList(value);
  if (Array.isArray(value)) {
    return Array.from(new Set(value.map((item) => String(item || "").trim()).filter(Boolean)));
  }
  return Array.from(new Set(String(value || "").split(/\r?\n+/).map((item) => item.trim()).filter(Boolean)));
}

function parseTagList(value) {
  const api = inputParsersApi();
  if (api && typeof api.parseTagList === "function") return api.parseTagList(value);
  if (Array.isArray(value)) {
    return Array.from(new Set(value.map((item) => String(item || "").trim()).filter(Boolean)));
  }
  return Array.from(new Set(String(value || "").split(",").map((item) => item.trim()).filter(Boolean)));
}

function safeId(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9._-]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 80) || "item";
}

