function updateTransferTreeClearButtons() {
  const sourceBtn = $("transferSourceTreeClearBtn");
  const targetBtn = $("transferTargetTreeClearBtn");
  const sourceUpBtn = $("transferSourceTreeUpBtn");
  const targetUpBtn = $("transferTargetTreeUpBtn");
  const sourceForwardBtn = $("transferSourceTreeForwardBtn");
  const targetForwardBtn = $("transferTargetTreeForwardBtn");
  const api = window.TransferTreeNavigation;
  const buttonState = api && typeof api.treeButtonState === "function"
    ? api.treeButtonState(state.transfer, { parentDirectoryPath })
    : {
        sourceClear: Boolean(state.transfer.source),
        targetClear: Boolean(state.transfer.target),
        sourceUp: Boolean(parentDirectoryPath(state.transfer.source?.path || "")),
        targetUp: Boolean(parentDirectoryPath(state.transfer.target?.path || "")),
        sourceForward: Boolean(Array.isArray(state.transfer.sourceForwardStack) && state.transfer.sourceForwardStack.length),
        targetForward: Boolean(Array.isArray(state.transfer.targetForwardStack) && state.transfer.targetForwardStack.length),
      };
  if (sourceBtn) sourceBtn.hidden = !buttonState.sourceClear;
  if (targetBtn) targetBtn.hidden = !buttonState.targetClear;
  if (sourceUpBtn) sourceUpBtn.hidden = !buttonState.sourceUp;
  if (targetUpBtn) targetUpBtn.hidden = !buttonState.targetUp;
  if (sourceForwardBtn) sourceForwardBtn.hidden = !buttonState.sourceForward;
  if (targetForwardBtn) targetForwardBtn.hidden = !buttonState.targetForward;
}

function renderTransferTree() {
  const box = $("transferTree");
  const meta = $("transferTreeMeta");
  if (!box || !meta) return;
  const source = state.transfer.source;
  if (!source) {
    meta.textContent = "选择源路径后显示文件树";
    box.innerHTML = transferPaneEmptyMarkup("还没有选择源路径", "填写上方路径，或点「浏览」「查看」加载目录。", { icon: "源" });
    updateTransferPreviewControls();
    updateTransferTreeClearButtons();
    return;
  }
  const prefix = source.serverName ? `${source.serverName} · ` : "";
  meta.textContent = prefix + (source.is_dir ? "文件夹，可展开查看并忽略子项" : "单个文件");
  box.innerHTML = renderTransferTreeNode(source, 0);
  updateTransferPreviewControls();
  updateTransferTreeClearButtons();
}

function renderTargetTreeNode(entry, level = 0) {
  const api = window.TransferTreeMarkup;
  if (api && typeof api.targetTreeNodeMarkup === "function") {
    return api.targetTreeNodeMarkup(entry, {
      level,
      tree: state.transfer.targetTree,
      selectedClassFor: (item) => normalizePathForCompare(item.path) === normalizePathForCompare(state.transfer.target?.path || "")
        ? " selected"
        : "",
    }, { escapeHtml });
  }
  const node = state.transfer.targetTree[entry.path];
  const open = Boolean(node?.open);
  const children = node?.entries || [];
  const icon = entry.is_dir ? (open ? "▾" : "▸") : "·";
  const selected = normalizePathForCompare(entry.path) === normalizePathForCompare(state.transfer.target?.path || "")
    ? " selected"
    : "";
  const row = api && typeof api.targetTreeNodeRowMarkup === "function"
    ? api.targetTreeNodeRowMarkup(entry, { level, icon, selectedClass: selected }, { escapeHtml })
    : `
    <div class="file-tree-row${level === 0 ? " root-row" : ""}${selected}" data-path="${escapeHtml(entry.path)}" data-dir="${entry.is_dir ? "1" : "0"}" style="padding-left:${6 + level * 18}px">
      <button class="file-toggle" type="button" data-action="toggle-target-node" data-path="${escapeHtml(entry.path)}" data-dir="${entry.is_dir ? "1" : "0"}" title="展开或收起这个目标目录">${icon}</button>
      <div class="file-tree-main">
        <span class="file-name" title="${escapeHtml(entry.path)}">[DIR] ${escapeHtml(entry.name || entry.path)}</span>
      </div>
    </div>
  `;
  if (!entry.is_dir || !open) return row;
  return row + children.map((child) => renderTargetTreeNode(child, level + 1)).join("");
}

function renderTargetTree() {
  const box = $("targetTree");
  const meta = $("targetTreeMeta");
  if (!box || !meta) return;
  const target = state.transfer.target;
  if (!target) {
    meta.textContent = "选择服务器后浏览目标目录";
    box.innerHTML = transferPaneEmptyMarkup("还没有选择目标目录", "选择目标服务器后点「浏览」，再选中目录。", { icon: "目标" });
    updateTransferTreeClearButtons();
    return;
  }
  meta.textContent = target.serverName ? `${target.serverName} · 点击目录可选择` : "点击目录可选择";
  box.innerHTML = renderTargetTreeNode(target, 0);
  updateTransferTreeClearButtons();
}

function defaultTransferPathForServer(_serverId) {
  return "";
}

function transferPathMemoryStateApi() {
  return window.TransferPathMemoryState && typeof window.TransferPathMemoryState === "object"
    ? window.TransferPathMemoryState
    : null;
}

function loadTransferPathByServer() {
  const stored = loadStoredJson(STORAGE_KEYS.transferPathByServer, { source: {}, target: {} });
  const api = transferPathMemoryStateApi();
  if (api && typeof api.normalizeStore === "function") return api.normalizeStore(stored);
  return {
    source: stored?.source && typeof stored.source === "object" ? stored.source : {},
    target: stored?.target && typeof stored.target === "object" ? stored.target : {},
  };
}

function saveTransferPathByServer() {
  if (!state.transfer.pathByServer) return;
  saveStoredJson(STORAGE_KEYS.transferPathByServer, state.transfer.pathByServer);
}

function transferPathPlaceholder(mode, serverId) {
  const server = serverById(serverId);
  if (server?.mode === "local") {
    return mode === "source" ? "/path/to/project/" : "/path/to/destination/";
  }
  return mode === "source" ? "/remote/path/to/project/" : "/remote/path/to/destination/";
}

function updateTransferPathPlaceholders() {
  const sourceInput = $("transferSourceInput");
  const targetInput = $("transferTargetInput");
  if (sourceInput) sourceInput.placeholder = transferPathPlaceholder("source", transferSourceServerId());
  if (targetInput) targetInput.placeholder = transferPathPlaceholder("target", transferTargetServerId());
}

function syncTransferPathInputsFromServers() {
  const sourceInput = $("transferSourceInput");
  const targetInput = $("transferTargetInput");
  const sourceId = transferSourceServerId();
  const targetId = transferTargetServerId();
  if (sourceInput) sourceInput.value = resolveTransferPathForServer("source", sourceId);
  if (targetInput) targetInput.value = resolveTransferPathForServer("target", targetId);
  updateTransferPathPlaceholders();
  updateTransferPathFavoriteButtons();
}

function rememberTransferPath(mode) {
  const isTarget = mode === "target";
  const serverId = isTarget ? transferTargetServerId() : transferSourceServerId();
  const path = isTarget ? transferTargetValue() : transferSourceValue();
  if (!state.transfer.pathByServer) state.transfer.pathByServer = { source: {}, target: {} };
  const api = transferPathMemoryStateApi();
  if (api && typeof api.rememberPath === "function") {
    const result = api.rememberPath(state.transfer.pathByServer, mode, serverId, path);
    state.transfer.pathByServer = result.store;
    if (result.changed) saveTransferPathByServer();
    return;
  }
  if (!serverId) return;
  state.transfer.pathByServer[isTarget ? "target" : "source"][serverId] = path;
  saveTransferPathByServer();
}

function resolveTransferPathForServer(mode, serverId) {
  if (!state.transfer.pathByServer) state.transfer.pathByServer = { source: {}, target: {} };
  const api = transferPathMemoryStateApi();
  if (api && typeof api.resolvePath === "function") {
    const result = api.resolvePath(state.transfer.pathByServer, mode, serverId, defaultTransferPathForServer);
    state.transfer.pathByServer = result.store;
    return result.path;
  }
  const bucket = state.transfer.pathByServer[mode] || {};
  if (Object.prototype.hasOwnProperty.call(bucket, serverId)) return bucket[serverId];
  return defaultTransferPathForServer(serverId);
}

function seedTransferPathMemory() {
  if (!state.transfer.pathByServer) state.transfer.pathByServer = loadTransferPathByServer();
  rememberTransferPath("source");
  rememberTransferPath("target");
  state.transfer.lastSourceServerId = transferSourceServerId();
  state.transfer.lastTargetServerId = transferTargetServerId();
}

function handleTransferSourceServerChange() {
  const select = $("transferSourceServerSelect");
  const input = $("transferSourceInput");
  const nextServerId = select?.value || "";
  const prevServerId = state.transfer.lastSourceServerId || "";
  if (!nextServerId) return;
  if (prevServerId && prevServerId !== nextServerId) {
    if (!state.transfer.pathByServer) state.transfer.pathByServer = { source: {}, target: {} };
    state.transfer.pathByServer.source[prevServerId] = transferSourceValue();
  }
  if (input) {
    input.value = prevServerId === nextServerId
      ? transferPathOnly(input.value)
      : resolveTransferPathForServer("source", nextServerId);
  }
  state.transfer.lastSourceServerId = nextServerId;
  state.transfer.source = null;
  state.transfer.tree = {};
  state.transfer.sourceForwardStack = [];
  renderTransferTree();
  updateTransferPathPlaceholders();
  renderTransferPathFavoriteBars();
  updateTransferPathFavoriteButtons();
}

function handleTransferTargetServerChange() {
  const select = $("transferTargetServerSelect");
  const input = $("transferTargetInput");
  const nextServerId = select?.value || "";
  const prevServerId = state.transfer.lastTargetServerId || "";
  if (!nextServerId) return;
  if (prevServerId && prevServerId !== nextServerId) {
    if (!state.transfer.pathByServer) state.transfer.pathByServer = { source: {}, target: {} };
    state.transfer.pathByServer.target[prevServerId] = transferTargetValue();
  }
  if (input) {
    input.value = prevServerId === nextServerId
      ? transferPathOnly(input.value)
      : resolveTransferPathForServer("target", nextServerId);
  }
  state.transfer.lastTargetServerId = nextServerId;
  state.transfer.target = null;
  state.transfer.targetTree = {};
  state.transfer.targetForwardStack = [];
  renderTargetTree();
  updateTransferPathPlaceholders();
  renderTransferPathFavoriteBars();
  updateTransferPathFavoriteButtons();
}

function transferTargetBrowsePath() {
  const raw = transferTargetValue();
  if (raw) return raw;
  return "/";
}

function transferSourceBrowsePath() {
  const raw = transferSourceValue();
  if (raw) return raw;
  return "/";
}

async function loadTransferSourceTree(path = transferSourceBrowsePath(), options = {}) {
  const box = $("transferTree");
  const meta = $("transferTreeMeta");
  const message = $("transferMessage");
  const serverId = transferSourceServerId();
  const server = serverById(serverId);
  const target = String(parseRsyncTargetPath(path) || path || "").trim();
  const previousPath = state.transfer.source?.path || "";
  if (!target) {
    state.transfer.source = null;
    state.transfer.tree = {};
    renderTransferTree();
    return;
  }
  if (options.rememberForward && previousPath && normalizePathForCompare(previousPath) !== normalizePathForCompare(target)) {
    const api = window.TransferTreeNavigation;
    state.transfer.sourceForwardStack = api && typeof api.rememberForwardStack === "function"
      ? api.rememberForwardStack(state.transfer.sourceForwardStack, previousPath, target, {
          normalizePathForCompare,
          limit: 8,
        })
      : [previousPath, ...(state.transfer.sourceForwardStack || []).filter((item) => normalizePathForCompare(item) !== normalizePathForCompare(previousPath))].slice(0, 8);
  } else if (!options.keepForward) {
    state.transfer.sourceForwardStack = [];
  }
  if (box) box.innerHTML = transferPaneLoadingMarkup("正在读取目录...");
  if (meta) meta.textContent = "加载中";
  if (message) {
    message.textContent = "";
    message.classList.remove("error");
  }
  try {
    const payload = await browseFiles(target, 300, { serverId });
    state.transfer.source = { ...(payload.selected || {}), serverName: server?.name || "" };
    state.transfer.tree = {};
    if (payload.selected?.is_dir) {
      state.transfer.tree[payload.selected.path] = {
        open: true,
        entries: payload.entries || [],
      };
      $("transferSourceInput").value = ensureDirectorySlash(payload.selected.path);
    } else if (payload.selected) {
      $("transferSourceInput").value = payload.selected.path;
    }
    renderTransferTree();
  } catch (error) {
    state.transfer.source = null;
    state.transfer.tree = {};
    renderTransferTree();
    if (message) {
      message.textContent = error.message;
      message.classList.add("error");
    }
  }
}

async function loadTransferTargetTree(path = transferTargetBrowsePath(), options = {}) {
  const box = $("targetTree");
  const meta = $("targetTreeMeta");
  const message = $("transferMessage");
  const serverId = transferTargetServerId();
  const server = serverById(serverId);
  const previousPath = state.transfer.target?.path || "";
  const target = String(parseRsyncTargetPath(path) || path || "").trim();
  if (options.rememberForward && previousPath && normalizePathForCompare(previousPath) !== normalizePathForCompare(target)) {
    const api = window.TransferTreeNavigation;
    state.transfer.targetForwardStack = api && typeof api.rememberForwardStack === "function"
      ? api.rememberForwardStack(state.transfer.targetForwardStack, previousPath, target, {
          normalizePathForCompare,
          limit: 8,
        })
      : [previousPath, ...(state.transfer.targetForwardStack || []).filter((item) => normalizePathForCompare(item) !== normalizePathForCompare(previousPath))].slice(0, 8);
  } else if (!options.keepForward) {
    state.transfer.targetForwardStack = [];
  }
  if (box) box.innerHTML = transferPaneLoadingMarkup("正在读取目标目录...");
  if (meta) meta.textContent = "加载中";
  if (message) {
    message.textContent = "";
    message.classList.remove("error");
  }
  try {
    const payload = await browseFiles(target || "", 300, { serverId, dirsOnly: true });
    const selected = { ...(payload.selected || {}), serverName: server?.name || "" };
    state.transfer.target = selected;
    state.transfer.targetTree = {};
    if (selected?.is_dir) {
      state.transfer.targetTree[selected.path] = {
        open: true,
        entries: payload.entries || [],
      };
      $("transferTargetInput").value = ensureDirectorySlash(selected.path);
    }
    renderTargetTree();
  } catch (error) {
    state.transfer.target = null;
    state.transfer.targetTree = {};
    renderTargetTree();
    if (message) {
      message.textContent = error.message;
      message.classList.add("error");
    }
  }
}

async function toggleTransferNode(path, isDir) {
  if (!isDir) return;
  const existing = state.transfer.tree[path];
  if (existing) {
    existing.open = !existing.open;
    renderTransferTree();
    return;
  }
  state.transfer.tree[path] = { open: true, entries: [] };
  renderTransferTree();
  try {
    const payload = await browseFiles(path, 300, { serverId: transferSourceServerId() });
    state.transfer.tree[path] = {
      open: true,
      entries: payload.entries || [],
    };
  } catch (error) {
    state.transfer.tree[path] = {
      open: true,
      entries: [{ name: error.message, path, is_dir: false, size_text: "", mtime: "" }],
    };
  }
  renderTransferTree();
}

async function toggleTransferTargetNode(path, isDir) {
  if (!isDir) return;
  const existing = state.transfer.targetTree[path];
  if (existing) {
    existing.open = !existing.open;
    renderTargetTree();
    return;
  }
  state.transfer.targetTree[path] = { open: true, entries: [] };
  renderTargetTree();
  try {
    const payload = await browseFiles(path, 300, {
      serverId: transferTargetServerId(),
      dirsOnly: true,
    });
    state.transfer.targetTree[path] = {
      open: true,
      entries: payload.entries || [],
    };
  } catch (error) {
    state.transfer.targetTree[path] = {
      open: true,
      entries: [{ name: error.message, path, is_dir: true, size_text: "", mtime: "" }],
    };
  }
  renderTargetTree();
}

function chooseTransferTargetDirectory(path) {
  const server = serverById(transferTargetServerId());
  $("transferTargetInput").value = ensureDirectorySlash(path);
  state.transfer.target = {
    name: pathBaseName(path),
    path,
    is_dir: true,
    serverName: server?.name || "",
  };
  renderTargetTree();
}

function transferProgressStateApi() {
  return window.TransferProgressState && typeof window.TransferProgressState === "object"
    ? window.TransferProgressState
    : null;
}

function parseTransferProgress(job, log) {
  const api = transferProgressStateApi();
  if (api && typeof api.parseTransferProgress === "function") return api.parseTransferProgress(job, log);
  if (job.status === "done") return 100;
  const matches = Array.from(String(log || "").matchAll(/(?:^|\s)(\d{1,3})%\s/g));
  const last = matches.length ? Number(matches[matches.length - 1][1]) : 0;
  return Math.max(0, Math.min(100, Number.isFinite(last) ? last : 0));
}

function lastTransferLine(log) {
  const api = transferProgressStateApi();
  if (api && typeof api.lastTransferLine === "function") return api.lastTransferLine(log);
  const lines = String(log || "")
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean)
    .filter((line) => !line.startsWith("[total-control] command:"));
  return lines.slice(-1)[0] || "等待输出...";
}

function renderTransferProgress() {
  const list = $("transferProgressList");
  if (!list) return;
  const jobs = state.jobs.filter((job) => job.kind === "transfer").slice(0, 20);
  if (!jobs.length) {
    const api = window.TransferProgressMarkup;
    list.innerHTML = api && typeof api.transferProgressEmptyMarkup === "function"
      ? api.transferProgressEmptyMarkup()
      : '<div class="empty compact-empty">暂无文件传输任务。</div>';
    return;
  }
  const api = window.TransferProgressMarkup;
  list.innerHTML = jobs
    .map((job) => {
      const cached = state.transfer.logs[job.id] || {};
      const pct = cached.progress ?? (job.status === "done" ? 100 : 0);
      const line = cached.line || (job.status === "running" ? "正在读取 rsync 输出..." : job.error || job.created_at);
      const canStop = ["running", "queued", "starting", "blocked"].includes(job.status);
      if (api && typeof api.transferProgressItemMarkup === "function") {
        return api.transferProgressItemMarkup(job, { canStop, line, pct }, { escapeHtml, zhStatus });
      }
      return `
        <div class="transfer-progress-item" onclick="showLog('${escapeHtml(job.id)}')">
          <div class="transfer-progress-head">
            <span class="transfer-progress-name" title="${escapeHtml(job.name)}">${escapeHtml(job.name)}</span>
            <span class="transfer-progress-actions">
              <span class="state ${escapeHtml(job.status)}">${escapeHtml(zhStatus(job.status))} · ${pct}%</span>
              ${canStop ? `<button class="stop-button compact" type="button" onclick="stopJob(event, '${escapeHtml(job.id)}')" title="取消这条文件传输任务">取消</button>` : ""}
            </span>
          </div>
          <div class="bar"><div class="bar-fill${job.status === "running" ? " busy" : ""}" style="width:${pct}%"></div></div>
          <div class="transfer-progress-line" title="${escapeHtml(line)}">${escapeHtml(line)}</div>
        </div>
      `;
    })
    .join("");
}

async function updateTransferProgress() {
  const jobs = state.jobs.filter((job) => job.kind === "transfer").slice(0, 20);
  if (!jobs.length) {
    renderTransferProgress();
    renderJobs();
    return;
  }
  await Promise.all(
    jobs.map(async (job) => {
      if (job.status === "done" && state.transfer.logs[job.id]) return;
      try {
        const payload = await fetchJson(`/api/jobs/${encodeURIComponent(job.id)}/log`);
        const log = payload.log || "";
        state.transfer.logs[job.id] = {
          progress: parseTransferProgress(job, log),
          line: lastTransferLine(log),
        };
      } catch (error) {
        state.transfer.logs[job.id] = {
          progress: 0,
          line: error.message,
        };
      }
    }),
  );
  renderTransferProgress();
  renderJobs();
}

function emptyFilePreviewState(serverId = "") {
  return {
    serverId: serverId || state.filePicker.serverId || "",
    path: "",
    text: "",
    encoding: "",
    truncated: false,
    kind: "",
    mimeType: "",
    sizeText: "",
    localPath: "",
    previewUrl: "",
    downloadUrl: "",
    inlineSupported: false,
    cached: false,
    error: "",
    loading: false,
  };
}

function clearFilePreview(message = "选择文件查看预览。") {
  state.filePreview = emptyFilePreviewState();
  renderFilePreview(message);
  renderTransferPreview("在源路径填单个文件后点“预览”，或从左侧文件树点“快览”。");
  updateTransferPreviewControls();
}

function clearTransferPreview() {
  clearFilePreview();
  renderTransferTree();
  renderSelectedSources();
  if (!$("filePickerModal").hidden) renderFilePicker(state.filePicker);
}

function updateTransferPreviewControls() {
  const hasPreview = Boolean(state.filePreview.path || state.filePreview.loading || state.filePreview.error);
  const closeBtn = $("transferPreviewClearBtn");
  const treeBtn = $("transferTreeClearPreviewBtn");
  if (closeBtn) closeBtn.hidden = !hasPreview;
  if (treeBtn) treeBtn.hidden = !hasPreview || !state.transfer.source;
}

function filePreviewKindLabel(kind) {
  const labels = {
    text: "文本快览",
    image: "图片快览",
    pdf: "PDF 快览",
    audio: "音频快览",
    video: "视频快览",
    binary: "文件快览",
  };
  return labels[String(kind || "")] || "文件快览";
}

function triggerBrowserDownload(url, filename = "") {
  if (!url) return;
  const anchor = document.createElement("a");
  anchor.href = url;
  if (filename) anchor.download = filename;
  anchor.rel = "noopener";
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
}

function downloadTextFile(text, filename, contentType = "text/plain;charset=utf-8") {
  const blob = new Blob([String(text ?? "")], { type: contentType });
  const url = URL.createObjectURL(blob);
  triggerBrowserDownload(url, filename || "download.txt");
  window.setTimeout(() => URL.revokeObjectURL(url), 1000);
}

function previewPathMatchesState(path, serverId = "") {
  const previewPath = normalizePathForCompare(state.filePreview.path || "");
  const nextPath = normalizePathForCompare(path || "");
  if (!previewPath || !nextPath || previewPath !== nextPath) return false;
  const activeServerId = String(state.filePreview.serverId || "");
  const targetServerId = String(serverId || "");
  if (!activeServerId || !targetServerId) return true;
  return activeServerId === targetServerId;
}

function buildFilePreviewDisplay(emptyMessage = "选择文件查看预览。") {
  const server = serverById(state.filePreview.serverId || state.filePicker.serverId || "");
  const api = window.FilePreviewMarkup;
  if (api && typeof api.buildFilePreviewDisplay === "function") {
    return api.buildFilePreviewDisplay(
      state.filePreview,
      {
        emptyMessage,
        serverName: server?.name || "",
      },
      { escapeHtml, formatPreviewText, pathBaseName },
    );
  }
  if (state.filePreview.loading) {
    return {
      title: "文件快览",
      meta: "正在下载到本机缓存",
      html: '<div class="file-preview-note">正在下载并准备预览内容...</div>',
      canOpen: false,
      canDownload: false,
    };
  }
  if (state.filePreview.error) {
    return {
      title: "文件快览",
      meta: "不可预览",
      html: `<div class="file-preview-note">${escapeHtml(state.filePreview.error)}</div>`,
      canOpen: false,
      canDownload: false,
    };
  }
  if (!state.filePreview.path) {
    return {
      title: "文件快览",
      meta: "选择文件后预览",
      html: `<div class="file-preview-note">${escapeHtml(emptyMessage)}</div>`,
      canOpen: false,
      canDownload: false,
    };
  }
  const kind = state.filePreview.kind || "binary";
  const title = pathBaseName(state.filePreview.path);
  const meta = [
    server?.name || (state.filePreview.serverId ? state.filePreview.serverId : "本机"),
    filePreviewKindLabel(kind),
    state.filePreview.sizeText || "",
    kind === "text" ? (state.filePreview.encoding || "utf-8") : "",
    state.filePreview.truncated ? "已截断" : "",
  ].filter(Boolean).join(" · ");
  const summary = `
    <div class="file-preview-summary">
      <strong>${state.filePreview.cached ? "已缓存到本机" : "当前本机文件"}</strong>
      <p class="file-preview-path" title="${escapeHtml(state.filePreview.localPath || state.filePreview.path)}">${escapeHtml(state.filePreview.localPath || state.filePreview.path)}</p>
    </div>
  `;
  if (kind === "text") {
    const previewText = formatPreviewText(state.filePreview.path, state.filePreview.text || "文件为空。");
    const htmlKind = pathBaseName(state.filePreview.path || "").toLowerCase().endsWith(".html")
      || pathBaseName(state.filePreview.path || "").toLowerCase().endsWith(".htm");
    if (htmlKind && state.filePreview.previewUrl) {
      return {
        title,
        meta,
        html: `${summary}<div class="file-preview-embed"><iframe sandbox="" src="${escapeHtml(state.filePreview.previewUrl)}" title="${escapeHtml(pathBaseName(state.filePreview.path))}"></iframe></div>`,
        canOpen: true,
        canDownload: Boolean(state.filePreview.downloadUrl),
      };
    }
    return {
      title,
      meta,
      html: `${summary}<pre class="file-preview-text">${escapeHtml(previewText)}</pre>`,
      canOpen: Boolean(state.filePreview.previewUrl),
      canDownload: Boolean(state.filePreview.downloadUrl),
    };
  }
  if (kind === "image" && state.filePreview.previewUrl) {
    return {
      title,
      meta,
      html: `${summary}<div class="file-preview-embed"><img src="${escapeHtml(state.filePreview.previewUrl)}" alt="${escapeHtml(pathBaseName(state.filePreview.path))}" loading="lazy" /></div>`,
      canOpen: true,
      canDownload: Boolean(state.filePreview.downloadUrl),
    };
  }
  if (kind === "pdf" && state.filePreview.previewUrl) {
    return {
      title,
      meta,
      html: `${summary}<div class="file-preview-embed"><iframe src="${escapeHtml(state.filePreview.previewUrl)}" title="${escapeHtml(pathBaseName(state.filePreview.path))}"></iframe></div>`,
      canOpen: true,
      canDownload: Boolean(state.filePreview.downloadUrl),
    };
  }
  if (kind === "audio" && state.filePreview.previewUrl) {
    return {
      title,
      meta,
      html: `${summary}<div class="file-preview-embed"><audio controls preload="metadata" src="${escapeHtml(state.filePreview.previewUrl)}"></audio></div>`,
      canOpen: true,
      canDownload: Boolean(state.filePreview.downloadUrl),
    };
  }
  if (kind === "video" && state.filePreview.previewUrl) {
    return {
      title,
      meta,
      html: `${summary}<div class="file-preview-embed"><video controls preload="metadata" src="${escapeHtml(state.filePreview.previewUrl)}"></video></div>`,
      canOpen: true,
      canDownload: Boolean(state.filePreview.downloadUrl),
    };
  }
  return {
    title,
    meta,
    html: `${summary}<div class="file-preview-note">这个文件类型暂不做内嵌展示，已经可以直接打开或下载本机缓存文件。</div>`,
    canOpen: Boolean(state.filePreview.previewUrl),
    canDownload: Boolean(state.filePreview.downloadUrl),
  };
}

function renderFilePreviewSurface(target, emptyMessage) {
  const box = $(target.boxId);
  const title = $(target.titleId);
  const meta = $(target.metaId);
  const openBtn = $(target.openBtnId);
  const downloadBtn = $(target.downloadBtnId);
  if (!box || !title || !meta) return;
  const display = buildFilePreviewDisplay(emptyMessage);
  title.textContent = display.title;
  meta.textContent = display.meta;
  const isEmpty = !state.filePreview.path && !state.filePreview.loading && !state.filePreview.error;
  box.classList.toggle("empty-state", isEmpty);
  box.innerHTML = display.html;
  if (openBtn) openBtn.hidden = !display.canOpen;
  if (downloadBtn) downloadBtn.hidden = !display.canDownload;
  if (target.boxId === "transferPreviewSurface") updateTransferPreviewControls();
}

function renderFilePreview(emptyMessage = "选择文件查看预览。") {
  renderFilePreviewSurface(
    {
      boxId: "filePreview",
      titleId: "filePreviewTitle",
      metaId: "filePreviewMeta",
      openBtnId: "filePreviewOpenBtn",
      downloadBtnId: "filePreviewDownloadBtn",
    },
    emptyMessage,
  );
}

function renderTransferPreview(emptyMessage = "在源路径填单个文件后点“预览”，或从左侧文件树点“快览”。") {
  renderFilePreviewSurface(
    {
      boxId: "transferPreviewSurface",
      titleId: "transferPreviewTitle",
      metaId: "transferPreviewMeta",
      openBtnId: "transferPreviewOpenBtn",
      downloadBtnId: "transferPreviewDownloadBtn",
    },
    emptyMessage,
  );
}

function openCurrentFilePreview() {
  if (state.filePreview.previewUrl) window.open(state.filePreview.previewUrl, "_blank", "noopener");
}

function downloadCurrentFilePreview() {
  if (state.filePreview.downloadUrl) {
    triggerBrowserDownload(state.filePreview.downloadUrl, pathBaseName(state.filePreview.path));
  }
}

async function previewFile(path, options = {}) {
  const serverId = options.serverId || "";
  state.filePreview = {
    serverId,
    path,
    text: "",
    encoding: "",
    truncated: false,
    kind: "",
    mimeType: "",
    sizeText: "",
    localPath: "",
    previewUrl: "",
    downloadUrl: "",
    inlineSupported: false,
    cached: false,
    error: "",
    loading: true,
  };
  renderFilePreview();
  renderTransferPreview();
  try {
    let payload;
    try {
      payload = await fetchFilePreviewAsset(path, { serverId, limitBytes: 131072 });
    } catch (primaryError) {
      if (!isLikelyTextPreviewPath(path)) throw primaryError;
      const textPayload = await readFileText(path, 131072, { serverId });
      payload = {
        path: textPayload.path || path,
        server_id: textPayload.server_id || serverId || "",
        text: textPayload.text || "",
        encoding: textPayload.encoding || "utf-8",
        truncated: Boolean(textPayload.truncated),
        preview_kind: "text",
        mime_type: "text/plain",
        size_text: "",
        local_path: textPayload.path || path,
        preview_url: "",
        download_url: "",
        inline_supported: true,
        cached: false,
      };
    }
    state.filePreview = {
      serverId: payload.server_id || serverId || "",
      path: payload.path || path,
      text: payload.text || "",
      encoding: payload.encoding || "utf-8",
      truncated: Boolean(payload.truncated),
      kind: payload.preview_kind || "binary",
      mimeType: payload.mime_type || "",
      sizeText: payload.size_text || "",
      localPath: payload.local_path || "",
      previewUrl: payload.preview_url || "",
      downloadUrl: payload.download_url || "",
      inlineSupported: Boolean(payload.inline_supported),
      cached: Boolean(payload.cached),
      error: "",
      loading: false,
    };
  } catch (error) {
    state.filePreview = {
      serverId,
      path,
      text: "",
      encoding: "",
      truncated: false,
      kind: "",
      mimeType: "",
      sizeText: "",
      localPath: "",
      previewUrl: "",
      downloadUrl: "",
      inlineSupported: false,
      cached: false,
      error: humanizeFetchError(error, "预览"),
      loading: false,
    };
  }
  renderFilePreview();
  renderTransferPreview();
  renderFilePicker(state.filePicker);
  renderTransferTree();
  renderSelectedSources();
}

async function previewFileInPicker(path) {
  await previewFile(path, { serverId: state.filePicker.serverId || "" });
}

async function previewFileInTransfer(path) {
  await previewFile(path, { serverId: transferSourceServerId() });
}

async function previewTransferSourceInput() {
  syncTransferSourceServerFromInput();
  const input = $("transferSourceInput");
  const message = $("transferMessage");
  const path = transferPathOnly(input?.value || "");
  if (!path) {
    renderTransferPreview("先填写源文件路径，或从左侧文件树点“快览”。");
    if (message) {
      message.textContent = "先填写一个源文件路径再预览。";
      message.classList.add("error");
    }
    return;
  }
  if (message) {
    message.textContent = `正在预览：${pathBaseName(path)}`;
    message.classList.remove("error");
  }
  await previewFileInTransfer(path);
  if (message && !state.filePreview.error) {
    message.textContent = `已缓存并预览：${pathBaseName(path)}`;
    message.classList.remove("error");
  } else if (message && state.filePreview.error) {
    message.textContent = state.filePreview.error;
    message.classList.add("error");
  }
}

function findFilePickerRow(path) {
  const api = filePickerNavigationApi();
  if (api && typeof api.findRow === "function") {
    return api.findRow(path, filePickerNavigationDeps());
  }
  const list = $("filePickerList");
  if (!list || !path) return null;
  const target = normalizePathForCompare(path);
  for (const row of list.querySelectorAll(".file-picker-row")) {
    if (normalizePathForCompare(row.dataset.path || "") === target) return row;
  }
  return null;
}

function restoreFilePickerScrollAfterRender() {
  const api = filePickerNavigationApi();
  if (api && typeof api.restoreScrollAfterRender === "function") {
    api.restoreScrollAfterRender(filePickerNavigationDeps());
    return;
  }
  const anchor = state.filePicker.scrollAnchorPath;
  if (!anchor) return;
  requestAnimationFrame(() => {
    const row = findFilePickerRow(anchor);
    if (row) row.scrollIntoView({ block: "center", inline: "nearest" });
    state.filePicker.scrollAnchorPath = "";
  });
}

function resetFilePickerNavigation() {
  const api = window.FilePickerNavigation;
  if (api && typeof api.resetNavigationState === "function") {
    state.filePicker = api.resetNavigationState(state.filePicker);
    return;
  }
  state.filePicker.navStack = [];
  state.filePicker.forwardStack = [];
  state.filePicker.selectedPath = "";
  state.filePicker.scrollAnchorPath = "";
}

function rememberFilePickerForwardPath(path) {
  const api = window.FilePickerNavigation;
  if (api && typeof api.rememberForwardPath === "function") {
    state.filePicker.forwardStack = api.rememberForwardPath(state.filePicker.forwardStack, path, {
      normalizePathForCompare,
      limit: 8,
    });
    return;
  }
  const value = String(path || "").trim();
  if (!value) return;
  const normalized = normalizePathForCompare(value);
  state.filePicker.forwardStack = [
    value,
    ...(Array.isArray(state.filePicker.forwardStack) ? state.filePicker.forwardStack : [])
      .filter((item) => normalizePathForCompare(item) !== normalized),
  ].slice(0, 8);
}

function updateFilePickerNavigationButtons() {
  const api = filePickerNavigationApi();
  if (api && typeof api.updateNavigationButtons === "function") {
    api.updateNavigationButtons(filePickerNavigationDeps());
    return;
  }
  const upBtn = $("filePickerUpBtn");
  const forwardBtn = $("filePickerForwardBtn");
  const buttonState = api && typeof api.navigationButtonState === "function"
    ? api.navigationButtonState(state.filePicker)
    : {
        canGoUp: Boolean(state.filePicker.parent),
        canGoForward: Boolean(Array.isArray(state.filePicker.forwardStack) && state.filePicker.forwardStack.length),
      };
  if (upBtn) upBtn.hidden = !buttonState.canGoUp;
  if (forwardBtn) forwardBtn.hidden = !buttonState.canGoForward;
}

function filePickerNavigationApi() {
  return window.FilePickerNavigation && typeof window.FilePickerNavigation === "object"
    ? window.FilePickerNavigation
    : null;
}

function filePickerNavigationDeps() {
  return {
    getElement: $,
    normalizePathForCompare,
    requestAnimationFrame: (callback) => requestAnimationFrame(callback),
    state,
    loadFilePicker,
    previewFileInPicker,
    rememberFilePickerForwardPath,
    updateFilePickerNavigationButtons,
  };
}

async function activateFilePickerRow(path = "", isDir = false) {
  return await filePickerNavigationApi()?.activateRow?.(path, isDir, filePickerNavigationDeps());
}

async function navigateFilePickerForward() {
  return await filePickerNavigationApi()?.navigateForward?.(filePickerNavigationDeps());
}

async function navigateFilePickerUp() {
  return await filePickerNavigationApi()?.navigateUp?.(filePickerNavigationDeps());
}

async function openFilePickerPathWithReset(path = "") {
  return await filePickerNavigationApi()?.openPath?.(path, filePickerNavigationDeps());
}

async function openFilePickerRootWithReset(path = "") {
  return await filePickerNavigationApi()?.openPath?.(path, filePickerNavigationDeps());
}

async function previewFilePickerPath(path = "") {
  return await filePickerNavigationApi()?.previewPath?.(path, filePickerNavigationDeps());
}

function markFilePickerPathInputChanged() {
  return filePickerNavigationApi()?.markPathInputChanged?.(filePickerNavigationDeps());
}

function renderRuntimeStoragePanel(payload = {}) {
  const stats = $("runtimeStorageStats");
  const previewAgeInput = $("runtimePreviewMaxAgeHours");
  const previewSizeInput = $("runtimePreviewMaxSizeMib");
  const logAgeInput = $("runtimeLogMaxAgeHours");
  const logFileInput = $("runtimeLogMaxFileMib");
  const logSizeInput = $("runtimeLogMaxSizeMib");
  const intervalInput = $("runtimeAutoIntervalMinutes");
  const remoteInput = $("runtimeRemoteCleanupEnabled");
  const message = $("runtimeStorageMessage");
  if (stats) {
    const api = window.RuntimeStorageSummary;
    if (api && typeof api.runtimeStorageStatsMarkup === "function") {
      stats.innerHTML = api.runtimeStorageStatsMarkup(payload, { escapeHtml, formatBytes });
    } else {
      const preview = payload.preview_cache || {};
      const localLogs = payload.local_logs || {};
      const remoteLogs = Array.isArray(payload.remote_logs) ? payload.remote_logs : [];
      const remoteOk = remoteLogs.filter((item) => !item.error && !item.skipped);
      const remoteIssues = remoteLogs.length - remoteOk.length;
      const remoteBytes = remoteOk.reduce((sum, item) => sum + Number(item.total_bytes || 0), 0);
      const remoteFiles = remoteOk.reduce((sum, item) => sum + Number(item.file_count || 0), 0);
      const paths = payload.paths || {};
      const localNewest = localLogs.newest_path
        ? `本机最新日志：<code>${escapeHtml(localLogs.newest_path)}</code>${localLogs.newest_at ? ` · ${escapeHtml(localLogs.newest_at)}` : ""}`
        : "本机最新日志：暂无";
      const localLargest = localLogs.largest_path
        ? `本机最大日志：<code>${escapeHtml(localLogs.largest_path)}</code> · ${escapeHtml(localLogs.largest_text || formatBytes(localLogs.largest_bytes))}`
        : "";
      const remoteNewestLines = remoteOk
        .filter((item) => item.newest_path)
        .slice(0, 3)
        .map((item) => {
          const serverName = item.server_name || item.server_id || "远程";
          const newestAt = item.newest_at ? ` · ${escapeHtml(item.newest_at)}` : "";
          return `远程最新日志：${escapeHtml(serverName)} <code>${escapeHtml(item.newest_path)}</code>${newestAt}`;
        });
      const lines = [
        `本机日志 <code>${escapeHtml(paths.local_logs || localLogs.log_dir || "data/logs")}</code>：${Number(localLogs.file_count || 0)} 个文件 · ${escapeHtml(localLogs.total_text || formatBytes(localLogs.total_bytes))}`,
        `远程日志 <code>${escapeHtml(paths.remote_logs || "$HOME/.total_control/logs")}</code>：${remoteOk.length} 台可读 · ${remoteFiles} 个文件 · ${escapeHtml(formatBytes(remoteBytes))}${remoteIssues ? ` · ${remoteIssues} 台不可读/已跳过` : ""}`,
        `预览缓存 <code>${escapeHtml(paths.preview_cache || preview.cache_dir || "/tmp/total-control-file-preview")}</code>：${Number(preview.entry_count || 0)} 项 · ${escapeHtml(preview.total_text || formatBytes(preview.total_bytes))}`,
      ];
      const detailLines = [localNewest, localLargest, ...remoteNewestLines].filter(Boolean);
      stats.innerHTML = `${lines.join("<br>")}${detailLines.length ? `<br>${detailLines.join("<br>")}` : ""}`;
    }
  }
  const settings = payload.settings || {};
  if (previewAgeInput) previewAgeInput.value = String(settings.preview_max_age_hours ?? 24);
  if (previewSizeInput) previewSizeInput.value = String(settings.preview_max_size_mib ?? 512);
  if (logAgeInput) logAgeInput.value = String(settings.log_max_age_hours ?? 168);
  if (logFileInput) logFileInput.value = String(settings.log_max_file_mib ?? 128);
  if (logSizeInput) logSizeInput.value = String(settings.log_max_size_mib ?? 2048);
  if (intervalInput) intervalInput.value = String(settings.auto_cleanup_interval_minutes ?? 60);
  if (remoteInput) remoteInput.checked = settings.remote_log_cleanup_enabled !== false;
  if (message && !message.classList.contains("error") && !message.textContent) message.textContent = "";
}

function renderRuntimeStatePanel(payload = {}) {
  const stats = $("runtimeStateStats");
  if (!stats) return;
  const api = window.RuntimeStorageSummary;
  if (api && typeof api.runtimeStateStatsMarkup === "function") {
    stats.innerHTML = api.runtimeStateStatsMarkup(payload, { escapeHtml });
    return;
  }
  const jobs = payload.jobs || {};
  const workspaces = payload.workspaces || {};
  const top = Array.isArray(workspaces.items) ? workspaces.items : [];
  const topRuns = top
    .filter((item) => Number(item.run_count || 0) > 0)
    .slice(0, 3)
    .map((item) => `${escapeHtml(item.name || item.workspace_id || "项目")} ${Number(item.run_count || 0)} 条`)
    .join(" · ");
  const lines = [
    `任务记录：${Number(jobs.total || 0)} 条 · 可清理 ${Number(jobs.completed || 0)} 条 · 活跃 ${Number(jobs.active || 0)} 条`,
    `项目运行记录：${Number(workspaces.total_runs || 0)} 条 · 活跃 ${Number(workspaces.active_runs || 0)} 条 · 事件 ${Number(workspaces.total_events || 0)} 条`,
  ];
  if (topRuns) lines.push(`记录较多：${topRuns}`);
  stats.innerHTML = lines.join("<br>");
}

function runtimeStorageSettingsInputPayload() {
  const previewAgeInput = $("runtimePreviewMaxAgeHours");
  const previewSizeInput = $("runtimePreviewMaxSizeMib");
  const logAgeInput = $("runtimeLogMaxAgeHours");
  const logFileInput = $("runtimeLogMaxFileMib");
  const logSizeInput = $("runtimeLogMaxSizeMib");
  const intervalInput = $("runtimeAutoIntervalMinutes");
  const remoteInput = $("runtimeRemoteCleanupEnabled");
  return {
    preview_max_age_hours: Number(previewAgeInput?.value || 0),
    preview_max_size_mib: Number(previewSizeInput?.value || 0),
    log_max_age_hours: Number(logAgeInput?.value || 0),
    log_max_file_mib: Number(logFileInput?.value || 0),
    log_max_size_mib: Number(logSizeInput?.value || 0),
    auto_cleanup_interval_minutes: Number(intervalInput?.value || 60),
    remote_log_cleanup_enabled: Boolean(remoteInput?.checked),
  };
}

const RUNTIME_STORAGE_CONTROL_IDS = [
  "runtimeStorageSaveBtn",
  "runtimeStorageCleanupBtn",
  "runtimeStoragePurgeBtn",
  "runtimeStateCleanupBtn",
  "runtimeStorageResetBtn",
];

function setRuntimeStorageControlsBusy(busy) {
  state.ui.runtimeStorageBusy = Boolean(busy);
  RUNTIME_STORAGE_CONTROL_IDS.forEach((id) => {
    const button = $(id);
    if (button) button.disabled = Boolean(busy);
  });
}

async function loadRuntimeStoragePanel() {
  const message = $("runtimeStorageMessage");
  try {
    const [payload, runtimeState] = await Promise.all([
      fetchJson("/api/admin/runtime-storage"),
      fetchJson("/api/admin/runtime-state"),
    ]);
    renderRuntimeStoragePanel(payload);
    renderRuntimeStatePanel(runtimeState);
    if (message) {
      message.textContent = "";
      message.classList.remove("error");
    }
  } catch (error) {
    if (message) {
      message.textContent = humanizeFetchError(error, "读取运行数据");
      message.classList.add("error");
    }
  }
}

async function saveRuntimeStorageSettings() {
  if (state.ui.runtimeStorageBusy) return;
  const message = $("runtimeStorageMessage");
  if (message) {
    message.textContent = "正在保存...";
    message.classList.remove("error");
  }
  setRuntimeStorageControlsBusy(true);
  try {
    const payload = await fetchJson("/api/admin/runtime-storage/settings", {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(runtimeStorageSettingsInputPayload()),
    });
    renderRuntimeStoragePanel(payload);
    if (message) message.textContent = "自动清理设置已保存。";
  } catch (error) {
    if (message) {
      message.textContent = humanizeFetchError(error, "保存设置");
      message.classList.add("error");
    }
  } finally {
    setRuntimeStorageControlsBusy(false);
  }
}

async function cleanupRuntimeStateNow() {
  if (state.ui.runtimeStorageBusy) return;
  const message = $("runtimeStorageMessage");
  if (!confirm("确定清理已完成/失败/停止的任务记录，并把每个项目的旧运行记录裁剪到最近 20 条吗？这不会删除运行日志、缓存、项目配置、聊天或密钥。")) return;
  if (message) {
    message.textContent = "正在清理运行记录...";
    message.classList.remove("error");
  }
  setRuntimeStorageControlsBusy(true);
  try {
    const payload = await fetchJson("/api/admin/runtime-state/cleanup", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        clear_completed_jobs: true,
        prune_workspace_runs: true,
        max_runs_per_workspace: 20,
      }),
    });
    renderRuntimeStatePanel(payload.status || {});
    if (message) {
      message.textContent = `已清理运行记录：任务 ${Number(payload.removed_jobs || 0)} 条，项目 run ${Number(payload.removed_runs || 0)} 条，事件 ${Number(payload.removed_events || 0)} 条。日志文件没有删除。`;
    }
    await loadStatus(true);
  } catch (error) {
    if (message) {
      message.textContent = humanizeFetchError(error, "清理运行记录");
      message.classList.add("error");
    }
  } finally {
    setRuntimeStorageControlsBusy(false);
  }
}

async function cleanupRuntimeStorageNow(removeAll = false) {
  if (state.ui.runtimeStorageBusy) return;
  const message = $("runtimeStorageMessage");
  const remoteInput = $("runtimeRemoteCleanupEnabled");
  const includeRemote = remoteInput?.checked !== false;
  const remoteText = includeRemote ? "、远程 $HOME/.total_control/logs" : "";
  const actionText = removeAll ? "清空" : "按当前阈值清理";
  const safetyText = removeAll
    ? "会删除范围内已有日志和预览缓存，但会保留正在运行任务和保留运行证据引用的日志。"
    : "会保留未超过当前时间/大小阈值的数据，以及正在运行任务和保留运行证据引用的日志。";
  if (!confirm(`确定${actionText} Total Control 的运行日志和预览缓存吗？范围仅限本机 data/logs${remoteText} 与 /tmp/total-control-file-preview；${safetyText}`)) return;
  if (message) {
    message.textContent = removeAll ? "正在清空..." : "正在按策略清理...";
    message.classList.remove("error");
  }
  setRuntimeStorageControlsBusy(true);
  try {
    const payload = await fetchJson("/api/admin/runtime-storage/cleanup", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        ...runtimeStorageSettingsInputPayload(),
        include_preview: true,
        include_logs: true,
        include_remote: includeRemote,
        remove_all: Boolean(removeAll),
      }),
    });
    renderRuntimeStoragePanel(payload.status || {});
    if (message) {
      const api = window.RuntimeStorageSummary;
      if (api && typeof api.runtimeStorageCleanupMessage === "function") {
        message.textContent = api.runtimeStorageCleanupMessage(payload, removeAll, { formatBytes });
      } else {
        const previewRemoved = payload.preview_cache?.removed_text || "0 B";
        const localRemoved = payload.local_logs?.removed_text || "0 B";
        const remoteRemoved = (payload.remote_logs || []).reduce((sum, item) => sum + Number(item.removed_bytes || 0), 0);
        const localPreserved = Number(payload.local_logs?.preserved_count || 0);
        const remotePreserved = (payload.remote_logs || []).reduce((sum, item) => sum + Number(item.preserved_count || 0), 0);
        const preservedText = localPreserved || remotePreserved
          ? ` 已保留活跃任务或运行证据日志 ${localPreserved + remotePreserved} 个。`
          : "";
        message.textContent = `${removeAll ? "已清空" : "已按策略清理"}：预览缓存 ${previewRemoved}，本机日志 ${localRemoved}，远程日志 ${formatBytes(remoteRemoved)}。${preservedText}`;
      }
    }
  } catch (error) {
    if (message) {
      message.textContent = humanizeFetchError(error, "清理运行数据");
      message.classList.add("error");
    }
  } finally {
    setRuntimeStorageControlsBusy(false);
  }
}

async function resetRuntimeStorageSettings() {
  if (state.ui.runtimeStorageBusy) return;
  const message = $("runtimeStorageMessage");
  if (!confirm("确定恢复默认自动清理策略吗？这不会删除已有日志或缓存。")) return;
  if (message) {
    message.textContent = "正在重置...";
    message.classList.remove("error");
  }
  setRuntimeStorageControlsBusy(true);
  try {
    const payload = await fetchJson("/api/admin/runtime-storage/reset", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: "{}",
    });
    renderRuntimeStoragePanel(payload);
    if (message) message.textContent = "已恢复默认清理策略。";
  } catch (error) {
    if (message) {
      message.textContent = humanizeFetchError(error, "重置清理策略");
      message.classList.add("error");
    }
  } finally {
    setRuntimeStorageControlsBusy(false);
  }
}

function renderFilePicker(payload = state.filePicker) {
  const roots = $("filePickerRoots");
  const list = $("filePickerList");
  const input = $("filePickerPathInput");
  const message = $("filePickerMessage");
  if (!roots || !list || !input) return;
  const title = $("filePickerTitle");
  const subtitle = $("filePickerSubtitle");
  const chooseDir = $("filePickerChooseDirBtn");
  const server = payload.serverId ? serverById(payload.serverId) : null;
  const filePickerMarkup = window.FilePickerMarkup;
  if (filePickerMarkup && typeof filePickerMarkup.filePickerHeaderText === "function") {
    const header = filePickerMarkup.filePickerHeaderText(payload, server);
    if (title) title.textContent = header.title;
    if (subtitle) subtitle.textContent = header.subtitle;
    if (chooseDir) chooseDir.textContent = header.chooseDirText;
  } else {
    if (title) title.textContent = payload.mode === "target" ? "选择目标目录" : "选择源文件或文件夹";
    if (subtitle) {
      subtitle.textContent = payload.mode === "target"
        ? `正在浏览 ${server?.name || "目标服务器"}，点目录进入，或用「选择」设为路径。`
        : server && server.mode !== "local"
          ? `正在浏览 ${server.name} 的文件系统，点目录进入、点文件快览。`
          : "浏览 WSL 可访问路径，例如 /mnt/e、/mnt/f、Home 和项目目录；点目录进入、点文件快览。";
    }
    if (chooseDir) chooseDir.textContent = payload.mode === "target" ? "选择当前目录" : "加入当前文件夹";
  }
  input.value = payload.path || "";
  const favoritesSidebarHtml = renderFilePickerFavoritesSidebar(payload.serverId, payload.path);
  if (filePickerMarkup && typeof filePickerMarkup.filePickerRootsMarkup === "function") {
    roots.innerHTML = filePickerMarkup.filePickerRootsMarkup(payload.roots || [], payload.path, favoritesSidebarHtml, { escapeHtml, normalizePathForCompare });
  } else {
    const rootButtons = (payload.roots || [])
      .map((root) => {
        const active = payload.path && normalizePathForCompare(payload.path).startsWith(normalizePathForCompare(root.path));
        return `
        <button class="root-button${active ? " active" : ""}" type="button" data-path="${escapeHtml(root.path)}" title="快速跳到这个常用根目录">
          <strong>${escapeHtml(root.label)}</strong>
          <span title="${escapeHtml(root.path)}">${escapeHtml(root.path)}</span>
        </button>
      `;
      })
      .join("");
    roots.innerHTML = `
    <div class="file-picker-sidebar-section">
      <div class="file-picker-sidebar-label">根目录</div>
      ${rootButtons || '<p class="file-picker-favorites-empty muted">暂无根目录。</p>'}
    </div>
    ${favoritesSidebarHtml}
  `;
  }
  const favoriteBtn = $("filePickerFavoriteBtn");
  if (favoriteBtn) {
    const favorited = Boolean(payload.path) && isTransferPathFavorite(payload.serverId, payload.path);
    favoriteBtn.textContent = favorited ? "已收藏" : "收藏";
    favoriteBtn.classList.toggle("active", favorited);
    favoriteBtn.disabled = !payload.path;
  }
  if (filePickerMarkup && typeof filePickerMarkup.filePickerEntriesMarkup === "function") {
    list.innerHTML = filePickerMarkup.filePickerEntriesMarkup(payload, {}, {
      escapeHtml,
      fmtDate,
      normalizePathForCompare,
      previewPathMatchesState,
      transferSourceItemByPath,
    });
  } else {
    const rows = (payload.entries || [])
      .map((entry) => {
        const selected = normalizePathForCompare(entry.path) === normalizePathForCompare(payload.selectedPath || "")
          ? " selected"
          : "";
        const previewActive = previewPathMatchesState(entry.path, payload.serverId || "") ? " preview-active" : "";
        const selectedSource = payload.mode === "target" ? null : transferSourceItemByPath(entry.path, entry.is_dir, payload.serverId);
        const sourceSelected = selectedSource ? " transfer-source-selected" : "";
        const chooseAction = selectedSource
          ? `<button class="file-action selected-source-toggle" type="button" data-action="remove-picker-source" data-source-key="${escapeHtml(selectedSource.key)}" title="取消加入这个待传源项">取消</button>`
          : `<button class="file-action${payload.mode !== "target" && entry.is_dir ? " primary-soft" : ""}" type="button" data-action="choose-picker" title="${payload.mode === "target" ? "把这个目录设为目标路径" : "把这个文件或目录加入源项"}">${payload.mode === "target" ? "选择" : "加入"}</button>`;
        const meta = [
          entry.is_dir ? "文件夹" : (entry.size_text || "文件"),
          fmtDate(entry.mtime) || "",
        ].filter(Boolean).join(" · ");
        if (filePickerMarkup && typeof filePickerMarkup.filePickerEntryRowMarkup === "function") {
          return filePickerMarkup.filePickerEntryRowMarkup(entry, {
            meta,
            mode: payload.mode,
            previewActiveClass: previewActive,
            selectedClass: selected,
            selectedSource,
            sourceSelectedClass: sourceSelected,
          }, { escapeHtml });
        }
        return `
      <div class="file-picker-row${selected}${previewActive}${sourceSelected}" data-path="${escapeHtml(entry.path)}" data-dir="${entry.is_dir ? "1" : "0"}">
        <div class="file-picker-row-main">
          <span class="file-kind">${entry.is_dir ? "DIR" : "FILE"}</span>
          <div class="file-picker-row-text">
            <span class="file-name" title="${escapeHtml(entry.path)}">${escapeHtml(entry.name)}</span>
            <span class="file-picker-row-meta" title="${escapeHtml(meta)}">${escapeHtml(meta)}</span>
          </div>
        </div>
        <div class="file-actions file-picker-row-actions">
          ${entry.is_dir ? "" : '<button class="file-action" type="button" data-action="preview-picker" title="把这个文件拉到本机缓存后快速预览">快览</button>'}
          ${chooseAction}
        </div>
      </div>
    `;
      })
      .join("");
    list.innerHTML = rows || (filePickerMarkup && typeof filePickerMarkup.filePickerEmptyListMarkup === "function"
      ? filePickerMarkup.filePickerEmptyListMarkup()
      : '<div class="empty compact-empty">目录为空。</div>');
  }
  if (message) {
    message.textContent = payload.truncated ? "目录项较多，仅显示前一部分。" : "";
    message.classList.remove("error");
  }
  updateFilePickerNavigationButtons();
  restoreFilePickerScrollAfterRender();
}

async function loadFilePicker(path = "") {
  const requestId = (state.filePicker.requestId || 0) + 1;
  state.filePicker.requestId = requestId;
  const mode = state.filePicker.mode || "source";
  const serverId = state.filePicker.serverId || "";
  const dirsOnly = Boolean(state.filePicker.dirsOnly);
  const list = $("filePickerList");
  const message = $("filePickerMessage");
  if (list) list.innerHTML = '<div class="empty compact-empty">正在读取目录...</div>';
  renderFilePreview();
  if (message) {
    message.textContent = "";
    message.classList.remove("error");
  }
  try {
    const payload = await browseFiles(path, 500, { serverId, dirsOnly });
    if (requestId !== state.filePicker.requestId) return;
    state.filePicker = {
      roots: payload.roots || [],
      path: payload.path || "",
      parent: payload.parent || "",
      entries: payload.entries || [],
      selected: payload.selected || null,
      truncated: payload.truncated,
      mode,
      serverId,
      dirsOnly,
      selectedPath: state.filePicker.selectedPath || "",
      scrollAnchorPath: state.filePicker.scrollAnchorPath || "",
      navStack: Array.isArray(state.filePicker.navStack) ? state.filePicker.navStack : [],
      forwardStack: Array.isArray(state.filePicker.forwardStack) ? state.filePicker.forwardStack : [],
      requestId,
    };
    renderFilePicker(state.filePicker);
  } catch (error) {
    if (requestId !== state.filePicker.requestId) return;
    const errorText = humanizeFetchError(error, "读取目录");
    if (list) {
      list.innerHTML = `<div class="empty compact-empty">${escapeHtml(errorText)}</div>`;
    }
    if (message) {
      message.textContent = errorText;
      message.classList.add("error");
    }
  }
}

async function openFilePicker(mode = "source") {
  state.filePicker.mode = mode;
  state.filePicker.serverId = mode === "target" ? transferTargetServerId() : transferSourceServerId();
  state.filePicker.dirsOnly = mode === "target";
  resetFilePickerNavigation();
  clearFilePreview();
  $("filePickerModal").hidden = false;
  const initialPath = mode === "target"
    ? transferTargetBrowsePath()
    : transferSourceBrowsePath();
  await loadFilePicker(initialPath);
}

function closeFilePicker() {
  $("filePickerModal").hidden = true;
  $("filePickerMessage").textContent = "";
  $("filePickerMessage").classList.remove("error");
}

async function chooseFilePickerPath(path, isDir) {
  if (state.filePicker.mode === "target") {
    chooseTransferTargetDirectory(path);
    closeFilePicker();
    await loadTransferTargetTree(path);
    return;
  }
  const sourcePath = transferPathOnly(path);
  $("transferSourceInput").value = isDir ? ensureDirectorySlash(sourcePath) : sourcePath;
  addTransferSource(sourcePath, isDir, { server: serverById(state.filePicker.serverId || transferSourceServerId()), silent: true });
  renderFilePicker(state.filePicker);
  const message = $("filePickerMessage");
  if (message) {
    message.textContent = `已加入待传源项：${pathBaseName(sourcePath)}`;
    message.classList.remove("error");
  }
  if (!state.transfer.source) await loadTransferSourceTree(sourcePath);
}

function jobSearchKey(job) {
  const api = jobStateApi();
  if (api && typeof api.jobSearchKey === "function") return api.jobSearchKey(job);
  return [
    job.id,
    job.name,
    job.kind,
    job.command_display || job.command,
    job.error,
    job.server_id,
    job.requested_server_id,
  ]
    .join(" ")
    .toLowerCase();
}

function jobMatchesKindFilter(job, value) {
  const api = jobStateApi();
  if (api && typeof api.matchesKindFilter === "function") return api.matchesKindFilter(job, value);
  if (!value) return true;
  return jobKindGroup(job) === value;
}

function jobMatchesStatusFilter(job, value) {
  const api = jobStateApi();
  if (api && typeof api.matchesStatusFilter === "function") return api.matchesStatusFilter(job, value);
  if (!value) return true;
  const status = String(job.status || "");
  if (value === "running") return ["running", "starting"].includes(status);
  if (value === "waiting") return ["queued", "blocked"].includes(status);
  if (value === "done") return status === "done";
  if (value === "failed") return ["failed", "stopped"].includes(status);
  if (value === "transfer") return job.kind === "transfer";
  return status === value;
}

function waitingQueuePositions() {
  return new Map(
    state.jobs
      .filter((job) => isWaitingJob(job))
      .slice()
      .sort((left, right) => jobQueueRank(left) - jobQueueRank(right))
      .map((job, index) => [job.id, index + 1]),
  );
}

function filteredJobs() {
  const query = state.jobFilters.query.trim().toLowerCase();
  const serverId = state.jobFilters.server;
  const status = state.jobFilters.status;
  const kind = state.jobFilters.kind;
  const sort = state.jobFilters.sort || "created_desc";
  const items = state.jobs
    .filter((job) => {
      if (query && !jobSearchKey(job).includes(query)) return false;
      if (serverId && String(job.server_id || "") !== serverId && String(job.requested_server_id || "") !== serverId) return false;
      if (!jobMatchesStatusFilter(job, status)) return false;
      if (!jobMatchesKindFilter(job, kind)) return false;
      return true;
    });
  items.sort((left, right) => {
    if (sort === "queue") {
      const leftWaiting = isWaitingJob(left);
      const rightWaiting = isWaitingJob(right);
      if (leftWaiting && rightWaiting) return jobQueueRank(left) - jobQueueRank(right);
      if (leftWaiting || rightWaiting) return leftWaiting ? -1 : 1;
    }
    if (sort === "duration_desc") {
      const delta = jobDurationMs(right) - jobDurationMs(left);
      if (delta !== 0) return delta;
    }
    const leftCreated = parseDateMs(left.created_at);
    const rightCreated = parseDateMs(right.created_at);
    if (sort === "created_asc") return leftCreated - rightCreated;
    return rightCreated - leftCreated;
  });
  return items.slice(0, 100);
}

function renderJobFilters() {
  const serverSelect = $("jobServerFilter");
  const statusSelect = $("jobStatusFilter");
  const kindSelect = $("jobTypeFilter");
  const sortSelect = $("jobSortSelect");
  const searchInput = $("jobSearch");
  if (!serverSelect || !statusSelect || !kindSelect || !sortSelect || !searchInput) return;
  const servers = Array.from(
    new Map(
      state.jobs
        .map((job) => {
          const serverId = String(job.server_id || job.requested_server_id || "");
          const server = serverById(serverId);
          return serverId ? [serverId, { id: serverId, name: server?.name || serverId }] : null;
        })
        .filter(Boolean),
    ).values(),
  ).sort((a, b) => String(a.name).localeCompare(String(b.name), "zh-Hans-CN", { numeric: true }));
  serverSelect.innerHTML = '<option value="">全部服务器</option>' +
    servers.map((server) => `<option value="${escapeHtml(server.id)}">${escapeHtml(server.name)}</option>`).join("");
  serverSelect.value = servers.some((server) => server.id === state.jobFilters.server) ? state.jobFilters.server : "";
  statusSelect.value = state.jobFilters.status || "";
  kindSelect.value = state.jobFilters.kind || "";
  sortSelect.value = state.jobFilters.sort || "created_desc";
  searchInput.value = state.jobFilters.query || "";
  state.jobFilters.server = serverSelect.value;
  state.jobFilters.kind = kindSelect.value;
  state.jobFilters.sort = sortSelect.value;
}

function loadJobIntoExecution(event, jobId) {
  consumeClick(event);
  const job = state.jobs.find((item) => item.id === jobId);
  if (!job) return;
  if (job.kind === "transfer") {
    const spec = job.metadata?.transfer_spec || {};
    const sourceItems = Array.isArray(spec.sources) ? spec.sources : [];
    state.transfer.sources = sourceItems
      .map((item) => {
        const serverId = item.server_id || "local";
        const server = serverById(serverId);
        const path = item.path || parseRsyncTargetPath(item.value || "") || item.value || "";
        const isDir = Boolean(item.is_dir) || String(item.value || "").trim().endsWith("/");
        return {
          key: transferSourceKey(serverId, path, isDir),
          serverId,
          serverName: server?.name || serverId,
          path,
          isDir,
          value: item.value || formatTransferSource(path, server, isDir),
        };
      })
      .filter((item) => item.path || item.value);
    state.transfer.ignores = Array.isArray(spec.excludes) ? spec.excludes.slice() : [];
    state.transfer.source = null;
    state.transfer.tree = {};
    state.transfer.target = null;
    state.transfer.targetTree = {};
    const sourceServerId = state.transfer.sources[0]?.serverId || "";
    if ($("transferSourceServerSelect") && sourceServerId) $("transferSourceServerSelect").value = sourceServerId;
    if ($("transferSourceInput")) {
      $("transferSourceInput").value = transferPathOnly(state.transfer.sources[0]?.path || state.transfer.sources[0]?.value || "");
    }
    if ($("transferTargetInput")) {
      $("transferTargetInput").value = transferPathOnly(spec.target || "");
    }
    if ($("transferTargetServerSelect") && spec.target_server_id) $("transferTargetServerSelect").value = spec.target_server_id;
    seedTransferPathMemory();
    const form = $("transferForm");
    if (form) {
      form.elements.checksum.checked = Boolean(spec.options?.checksum);
      form.elements.size_only.checked = Boolean(spec.options?.size_only ?? true);
      form.elements.resume_partial.checked = Boolean(spec.options?.resume_partial ?? true);
    }
    syncIgnoreInputFromState();
    renderSelectedSources();
    renderTransferSourceOptions();
    renderTransferTargetOptions();
    renderTransferTree();
    renderTargetTree();
    switchProductTab("exec");
    switchExecTab("transfer");
    persistFormState("transferForm");
    $("transferMessage").textContent = `已载入 ${job.id}`;
    $("transferMessage").classList.remove("error");
    return;
  }
  const form = $("jobForm");
  if (!form) return;
  state.selectedServer = String(job.requested_server_id || job.server_id || state.selectedServer || "");
  state.selectedGpu = String(job.requested_gpu_index ?? job.gpu_index ?? "auto");
  saveStoredValue(STORAGE_KEYS.selectedServer, state.selectedServer);
  renderFormOptions();
  $("serverSelect").value = $("serverSelect").querySelector(`option[value="${CSS.escape(state.selectedServer)}"]`)
    ? state.selectedServer
    : $("serverSelect").value;
  renderFormOptions();
  $("gpuSelect").value = Array.from($("gpuSelect").options).some((option) => option.value === String(state.selectedGpu))
    ? String(state.selectedGpu)
    : "auto";
  form.elements.command.value = job.command_display || job.command || "";
  form.elements.cwd.value = job.cwd || "";
  form.elements.env_name.value = job.env_name || "";
  form.elements.min_free_mib.value = job.min_free_mib ?? 0;
  form.elements.max_gpu_util.value = job.max_gpu_util ?? 10;
  form.elements.wait_for_idle.checked = Boolean(job.wait_for_idle);
  clearJobSourceBinding();
  switchProductTab("exec");
  switchExecTab("job");
  persistFormState("jobForm");
  $("formMessage").textContent = `已载入 ${job.id}`;
  $("formMessage").classList.remove("error");
}

async function reorderQueuedJob(event, jobId, direction) {
  consumeClick(event);
  const button = event.currentTarget;
  if (button) button.disabled = true;
  try {
    await fetchJson(`/api/jobs/${encodeURIComponent(jobId)}/reorder`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ direction }),
    });
    await loadStatus(true);
  } catch (error) {
    showActionError(error);
  }
}

