async function runGlobalToolTest() {
  const tool = state.toolDefinitionDraft && Object.keys(state.toolDefinitionDraft).length
    ? normalizeGlobalToolDefinitionDraft(state.toolDefinitionDraft)
    : selectedGlobalTool();
  const toolId = String(tool?.id || state.selectedGlobalToolId || "").trim();
  if (!toolId || !state.selectedGlobalToolId) {
    state.toolDefinitionTest.error = "先保存或选择一个工具定义。";
    renderManageToolModule();
    return;
  }
  let args = {};
  try {
    args = JSON.parse(state.toolDefinitionTest.argumentsText || "{}");
    if (!args || typeof args !== "object" || Array.isArray(args)) throw new Error("参数必须是 JSON object");
  } catch (error) {
    state.toolDefinitionTest.error = `参数 JSON 无效：${error.message || error}`;
    state.toolDefinitionTest.result = null;
    renderManageToolModule();
    return;
  }
  state.toolDefinitionTest = {
    ...state.toolDefinitionTest,
    toolId,
    busy: true,
    error: "",
    result: null,
  };
  renderManageToolModule();
  try {
    const payload = await fetchJson(`/api/tool-definitions/${encodeURIComponent(toolId)}/test`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        workspace_id: state.toolDefinitionTest.workspaceId || "",
        arguments: args,
      }),
    });
    state.toolDefinitionTest.result = payload.test || payload;
    setWorkspaceManageMessage("工具安全测试已完成。");
  } catch (error) {
    state.toolDefinitionTest.error = error.message || String(error);
  } finally {
    state.toolDefinitionTest.busy = false;
    renderManageToolModule();
  }
}

function stableJsonText(value) {
  return JSON.stringify(value ?? {}, null, 2);
}

function currentAgentDebugTranscript(scope = "") {
  const normalizedScope = String(scope || "").trim();
  if (normalizedScope === "manage" && state.manageAgentDebug?.result?.debug) {
    return state.manageAgentDebug.result.debug;
  }
  if (normalizedScope === "workspace" && state.workspaceAgentDebug?.result) {
    return state.workspaceAgentDebug.result;
  }
  if (state.manageAgentDebug?.result?.debug) return state.manageAgentDebug.result.debug;
  if (state.workspaceAgentDebug?.result) return state.workspaceAgentDebug.result;
  return null;
}

async function copyAgentDebugTranscript(scope = "") {
  const transcript = currentAgentDebugTranscript(scope);
  if (!transcript) throw new Error("还没有可复制的 Agent 调试结果。");
  await copyTextToClipboard(stableJsonText(transcript));
}

async function copyToolTestResult() {
  const result = state.toolDefinitionTest?.result;
  if (!result) throw new Error("还没有可复制的工具测试结果。");
  await copyTextToClipboard(stableJsonText(result));
}

async function saveManageProviderProfile() {
  const profile = selectedProviderProfile();
  if (!profile) {
    state.ui.providerTestResult = { text: "先新增或选择一个 Provider Profile。", isError: true, models: [] };
    renderManageAiModule();
    return;
  }
  if (!providerProfileIsValid(profile)) {
    const searchEndpointRequired = providerProfileKind(profile) === "search" && searchProviderOption(profile.vendor).endpoint_required;
    const requiredText = providerProfileKind(profile) === "search"
      ? `显示名 / Search Provider${searchEndpointRequired ? " / Endpoint" : ""}${providerProfileRequiresApiKey(profile) ? " / API Key" : ""}`
      : providerProfileRequiresApiKey(profile)
        ? "显示名 / 厂商 / Base URL / Model / API Key"
        : "显示名 / 厂商 / Base URL / Model";
    state.ui.providerTestResult = { text: `✗ 必填项未填全（标红的：${requiredText}），无法保存。`, isError: true, models: [] };
    renderManageAiModule();
    return;
  }
  clearTimeout(state._providerProfileSaveTimeout);
  state._providerProfileSaveTimeout = 0;
  try {
    await saveProviderProfile(profile, { forceCreate: Boolean(profile.is_new) });
    state.ui.providerTestResult = { text: "✓ Provider Profile 已保存。", isError: false, models: [] };
    renderManageAiModule();
  } catch (error) {
    state.ui.providerTestResult = { text: `✗ 保存失败：${error.message || error}`, isError: true, models: [] };
    renderManageAiModule();
  }
}

async function testManageProviderProfile() {
  const profile = selectedProviderProfile();
  if (!profile) {
    state.ui.providerTestResult = { text: "先新增或选择一个 Provider Profile。", isError: true, models: [] };
    renderManageAiModule();
    return;
  }
  state.ui.providerTestResult = { text: "正在测试连接…", isError: false, models: [] };
  renderManageAiModule();
  const kind = providerProfileKind(profile);
  const body = profile.api_key
    ? {
        kind,
        provider: profile.vendor,
        base_url: profile.base_url,
        api_key: profile.api_key,
        model: kind === "llm" ? profile.model : "",
        query: "RelayGraph search provider smoke",
      }
    : { profile_id: profile.id, model: kind === "llm" ? profile.model : "", query: "RelayGraph search provider smoke" };
  try {
    const res = await fetchJson("/api/provider-profiles/test", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    });
    const t = res.test || {};
    const models = Array.isArray(t.available_models) ? t.available_models : [];
    if (kind === "search" || t.kind === "search") {
      state.ui.providerTestResult = t.success
        ? { text: `✓ 搜索接入可用 · ${t.provider || ""} · ${t.provider_status || t.status || "ready"} · ${t.result_count || 0} 结果 · ${t.latency_ms || 0}ms`, isError: false, models: [] }
        : { text: `✗ 搜索接入未就绪 · ${t.provider || ""} · ${t.error || t.provider_status || "未知错误"}`, isError: true, models: [] };
    } else {
      state.ui.providerTestResult = t.success
        ? { text: `✓ 连接成功 · ${t.provider || ""} ${t.model || ""} · ${t.latency_ms || 0}ms · ${t.total_tokens || 0} tokens`, isError: false, models }
        : { text: `✗ 连接失败 · ${t.base_url || ""} · ${t.error || "未知错误"}${models.length ? "（下方可点选正确模型）" : ""}`, isError: true, models };
    }
  } catch (error) {
    state.ui.providerTestResult = { text: `✗ 测试请求失败：${error.message || error}`, isError: true, models: [] };
  }
  renderManageAiModule();
}

